-- 2월 DDC 결과: 1위 liam(+5만), 2위 dad(+3만), 3위 mom(0), 4위 jin(-3만), 5위 sean(-5만)
-- jin: 기본12 + 매니저보상5 - DDC4등3 = 14만원
UPDATE monthly_allowances SET bonus=5, penalty=3, final_allowance=14, breakdown_formula='기본 12만원 + 매니저보상 +5 - DDC 4등 -3 = 14만원' WHERE month='2026-03' AND member_id='jin';
-- liam: 기본5 + DDC1등5 = 10만원
UPDATE monthly_allowances SET bonus=5, penalty=0, final_allowance=10, breakdown_formula='기본 5만원 + DDC 1등 +5 = 10만원' WHERE month='2026-03' AND member_id='liam';
-- sean: 기본12 - DDC5등5 - RCR벌금3 = 4만원 (sean penalty=3이었으므로 RCR벌금 확인 필요)
SELECT member_id, base_allowance, bonus, penalty, final_allowance, breakdown_formula FROM monthly_allowances WHERE month='2026-03';

